const clean = (value, max) => String(value ?? '').replace(/[\u0000-\u001f\u007f]/g, ' ').replace(/\s+/g, ' ').trim().slice(0, max);
const execution = $json.execution ?? {};
const workflow = $json.workflow ?? {};
const message = clean(execution.error?.message, 300);
const retryable = /(?:^|\D)(429|500|502|503|504)(?:\D|$)|timeout|econnreset/i.test(message);
const envelope = { workflowId: clean(workflow.id, 128), workflowName: clean(workflow.name, 120), executionId: clean(execution.id, 128), lastNode: clean(execution.lastNodeExecuted, 120), occurredAt: clean(execution.stoppedAt ?? execution.startedAt, 40), errorClass: retryable ? 'retryable' : 'manual-review', message };
return [{ json: { envelope, retryable, rawExecutionStored: false, note: 'Connect to an approved log or alert destination after reviewing retention and access controls' } }];
